#!/bin/bash
set -e # Termina se c'è un errore

echo "Inizio ricostruzione progetto..."

mkdir -p "core"
mkdir -p "core/dist"
echo "Creating core/dist/index.d.ts..."
cat << 'END_OF_FILE_CONTENT' > "core/dist/index.d.ts"
