  description: string;
  contractHref: string;
  transport: {
    kind: 'window-message';
    requestType: string;
    resultType: string;
    target: 'window';
  };
  capabilities: {
    resources: Array<{
      uri: string;
      name: string;
      mimeType: string;
      description: string;
    }>;
  };
